{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem requires finding a sequence of sibling merges to transform one tree into another. This is a structural transformation problem that can be broken down into identifying which nodes must be merged and determining the correct order of operations to ensure validity (merging siblings only).",
  "helpers": [
    {
      "label": "structural_analyzer",
      "instructions": "Analyze the initial tree and the final tree to identify the set of required merge operations. For each node in the final tree, determine which nodes from the initial tree must have been merged to form it. Specifically, identify pairs of siblings in the initial tree that must be merged because they belong to the same parent in the final tree or because one is a descendant of the other in the final structure. Output a list of pairs (u, v) representing nodes that must be merged, where u and v are siblings in the current state of the tree."
    },
    {
      "label": "sequence_scheduler",
      "instructions": "Given a set of required merge operations (u, v) where u and v are siblings, determine a valid execution order. A merge is valid only if u and v are currently siblings. Since merging two siblings changes the sibling set for the parent, the order matters. Use a topological sort or a greedy approach based on tree depth (e.g., bottom-up) to ensure that when a merge (u, v) is called, u and v are indeed siblings in the evolving tree structure."
    }
  ],
  "synthesis_brief": "Combine the list of required merge pairs from the structural_analyzer with the valid execution order from the sequence_scheduler to produce the final list of operations. The final output should be the count of operations followed by each pair."
}

